const _ = require('lodash');
const problemsData = require('../../data/problems.json');

/**
 * Fetch problems with optional filtering by difficulty, limit, and skill tags.
 * @param {Object} params
 * @param {string|string[]} [params.skillTags] - Skill tags to filter by (case-insensitive, comma-separated string or array).
 * @param {string} [params.difficulty] - Difficulty filter.
 * @param {number} [params.limit] - Limit number of results.
 * @returns {Object} - { problems: Array, metadata: Object }
 */
function getProblems(params = {}) {
  let { skillTags, difficulty, limit } = params;

  // Normalize skillTags to array of lowercase strings
  let normalizedTags = [];
  if (skillTags) {
    if (Array.isArray(skillTags)) {
      normalizedTags = skillTags.map(t => String(t).toLowerCase().trim()).filter(t => t.length > 0);
    } else if (typeof skillTags === 'string') {
      normalizedTags = skillTags.split(',').map(t => t.toLowerCase().trim()).filter(t => t.length > 0);
    }
  }

  // Filter problems
  let filtered = problemsData;

  if (difficulty) {
    filtered = filtered.filter(p => p.difficulty === difficulty);
  }

  if (normalizedTags.length > 0) {
    filtered = filtered.filter(p => {
      if (!p.tags || !Array.isArray(p.tags)) return false;
      const problemTags = p.tags.map(t => t.toLowerCase());
      // Check if problemTags contain all normalizedTags
      return normalizedTags.every(tag => problemTags.includes(tag));
    });
  }

  // Stable sort by id ascending
  filtered = _.sortBy(filtered, ['id']);

  if (limit && Number.isInteger(limit) && limit > 0) {
    filtered = filtered.slice(0, limit);
  }

  // Metadata includes normalized skillTags filters
  const metadata = {
    skillTags: normalizedTags,
    difficulty: difficulty || null,
    limit: limit || null,
    totalCount: filtered.length
  };

  return { problems: filtered, metadata };
}

module.exports = {
  getProblems
};
